import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { formatDistanceToNow, format } from 'date-fns';
import Navbar from '../components/ui/Navbar';
import api from '../lib/api';
import useAuthStore from '../store/authStore';
import toast from 'react-hot-toast';

export default function ListingDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuthStore();
  const [listing, setListing] = useState(null);
  const [loading, setLoading] = useState(true);
  const [claiming, setClaiming] = useState(false);

  useEffect(() => {
    api.get(`/listings/${id}`)
      .then((res) => setListing(res.data.data))
      .catch(() => toast.error('Listing not found.'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleClaim = async () => {
    setClaiming(true);
    try {
      await api.post(`/bookings/${id}`);
      toast.success('Batch claimed!');
      setListing((l) => ({ ...l, status: 'claimed' }));
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to claim.');
    } finally {
      setClaiming(false);
    }
  };

  if (loading) return <div className="min-h-screen bg-surface-950 flex items-center justify-center"><p className="text-surface-200">Loading...</p></div>;
  if (!listing) return null;

  return (
    <div className="min-h-screen bg-surface-950">
      <Navbar />
      <div className="max-w-2xl mx-auto px-4 py-8">
        <button onClick={() => navigate(-1)} className="text-sm text-surface-200 hover:text-white mb-6 flex items-center gap-1">
          ← Back
        </button>

        {listing.imageUrl && (
          <img src={listing.imageUrl} alt={listing.title} className="w-full aspect-video object-cover rounded-2xl mb-6" />
        )}

        <div className="bg-surface-900 border border-surface-800 rounded-2xl p-6">
          <div className="flex items-start justify-between gap-4 mb-4">
            <h1 className="text-xl font-bold text-white">{listing.title}</h1>
            <span className="text-sm bg-surface-800 text-surface-200 px-3 py-1 rounded-full capitalize flex-shrink-0">
              {listing.foodType}
            </span>
          </div>

          {listing.description && (
            <p className="text-surface-200 text-sm mb-4">{listing.description}</p>
          )}

          <div className="grid grid-cols-2 gap-3 mb-4 text-sm">
            <div className="bg-surface-800 rounded-xl p-3">
              <p className="text-surface-200 text-xs mb-0.5">Quantity</p>
              <p className="text-white font-medium">{listing.quantity} {listing.quantityUnit}</p>
            </div>
            <div className="bg-surface-800 rounded-xl p-3">
              <p className="text-surface-200 text-xs mb-0.5">Expires</p>
              <p className="text-white font-medium">{formatDistanceToNow(new Date(listing.expiresAt), { addSuffix: true })}</p>
            </div>
            <div className="bg-surface-800 rounded-xl p-3">
              <p className="text-surface-200 text-xs mb-0.5">Posted by</p>
              <p className="text-white font-medium">{listing.donor?.organizationName || listing.donor?.name}</p>
            </div>
            <div className="bg-surface-800 rounded-xl p-3">
              <p className="text-surface-200 text-xs mb-0.5">Pickup</p>
              <p className="text-white font-medium">{listing.location?.city}</p>
            </div>
          </div>

          <p className="text-sm text-surface-200 mb-1">📍 {listing.location?.address}</p>
          {listing.donor?.phone && <p className="text-sm text-surface-200 mb-4">📞 {listing.donor.phone}</p>}
          {listing.handlingInstructions && (
            <p className="text-sm text-brand-400 mb-4">ℹ {listing.handlingInstructions}</p>
          )}

          {user?.role === 'receiver' && listing.status === 'available' && (
            <button onClick={handleClaim} disabled={claiming}
              className="w-full bg-brand-600 hover:bg-brand-500 disabled:opacity-60 text-white font-semibold py-3 rounded-xl text-sm transition-colors mt-2">
              {claiming ? 'Claiming...' : 'Claim This Batch'}
            </button>
          )}

          {listing.status === 'claimed' && (
            <div className="text-center py-3 bg-surface-800 rounded-xl text-surface-200 text-sm">
              This batch has been claimed.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
