import React, { useEffect, useState } from 'react';
import { formatDistanceToNow } from 'date-fns';
import Navbar from '../components/ui/Navbar';
import api from '../lib/api';
import toast from 'react-hot-toast';

export default function MyBookingsPage() {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/bookings/my-bookings')
      .then((res) => setBookings(res.data.data))
      .catch(() => toast.error('Failed to load bookings.'))
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="min-h-screen bg-surface-950">
      <Navbar />
      <div className="max-w-3xl mx-auto px-4 py-8">
        <h1 className="text-2xl font-bold text-white mb-6">My Claims</h1>

        {loading ? (
          <p className="text-surface-200">Loading...</p>
        ) : bookings.length === 0 ? (
          <div className="text-center py-16 border border-dashed border-surface-800 rounded-2xl">
            <p className="text-surface-200">No claims yet.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {bookings.map((b) => (
              <div key={b._id} className="bg-surface-900 border border-surface-800 rounded-2xl overflow-hidden">
                <div className="flex gap-4 p-4">
                  {b.listing?.imageUrl && (
                    <img src={b.listing.imageUrl} alt={b.listing.title}
                      className="w-20 h-20 object-cover rounded-xl flex-shrink-0" />
                  )}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-2">
                      <h3 className="font-semibold text-white text-sm leading-tight">{b.listing?.title}</h3>
                      <span className={`text-xs px-2 py-1 rounded-full font-medium flex-shrink-0 ${
                        b.status === 'completed' ? 'bg-green-900 text-green-300'
                        : b.status === 'cancelled' ? 'bg-red-900 text-red-300'
                        : 'bg-brand-900 text-brand-300'
                      }`}>
                        {b.status}
                      </span>
                    </div>
                    <p className="text-surface-200 text-xs mt-1">
                      {b.donor?.organizationName || b.donor?.name}
                    </p>
                    <p className="text-surface-200 text-xs mt-0.5">
                      📍 {b.listing?.location?.address}, {b.listing?.location?.city}
                    </p>
                    {b.donor?.phone && (
                      <p className="text-brand-400 text-xs mt-1 font-medium">
                        📞 {b.donor.phone}
                      </p>
                    )}
                    <p className="text-surface-200 text-xs mt-2">
                      Claimed {formatDistanceToNow(new Date(b.createdAt), { addSuffix: true })}
                    </p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
