import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/ui/Navbar';
import api from '../lib/api';
import toast from 'react-hot-toast';

export default function CreateListingPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [preview, setPreview] = useState(null);
  const [form, setForm] = useState({
    title: '', description: '', foodType: 'veg',
    quantity: '', quantityUnit: 'servings',
    expiresAt: '', handlingInstructions: '',
    'location.address': '', 'location.city': '',
  });
  const [image, setImage] = useState(null);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setImage(file);
    setPreview(URL.createObjectURL(file));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true); // ✅ This is the correct state setter function!

    const formData = new FormData();
    Object.entries(form).forEach(([k, v]) => formData.append(k, v));
    if (image) formData.append('image', image);

    try {
      await api.post('/listings', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      toast.success('Listing created!');
      navigate('/donor');
    } catch (err) {
      const errors = err.response?.data?.errors;
      if (errors?.length) {
        toast.error(errors[0].message);
      } else {
        toast.error(err.response?.data?.message || 'Failed to create listing.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-surface-950">
      <Navbar />
      <div className="max-w-2xl mx-auto px-4 py-8">
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-white">Log Excess Food</h1>
          <p className="text-surface-200 text-sm mt-0.5">Make your surplus available to local charities.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Image Upload */}
          <div>
            <label className="block text-sm text-surface-200 mb-1.5">Food Photo</label>
            <label className="block cursor-pointer">
              <div className={`border-2 border-dashed rounded-2xl transition-colors ${preview ? 'border-brand-600' : 'border-surface-700 hover:border-surface-500'} overflow-hidden`}>
                {preview ? (
                  <img src={preview} alt="Preview" className="w-full h-48 object-cover" />
                ) : (
                  <div className="flex flex-col items-center justify-center h-36 text-surface-200">
                    <span className="text-3xl mb-2">📷</span>
                    <span className="text-sm">Click to upload a photo</span>
                    <span className="text-xs mt-1">JPG, PNG, WEBP · Max 5MB</span>
                  </div>
                )}
              </div>
              <input type="file" accept="image/*" className="hidden" onChange={handleImageChange} />
            </label>
          </div>

          <Field label="Listing Title *">
            <input type="text" required value={form.title}
              onChange={(e) => setForm({ ...form, title: e.target.value })}
              className={inputClass} placeholder="e.g. 15 Servings of Chicken Biryani" />
          </Field>

          <Field label="Description">
            <textarea rows={3} value={form.description}
              onChange={(e) => setForm({ ...form, description: e.target.value })}
              className={`${inputClass} resize-none`} placeholder="Any notes about the food..." />
          </Field>

          <div className="grid grid-cols-2 gap-4">
            <Field label="Food Type *">
              <select required value={form.foodType}
                onChange={(e) => setForm({ ...form, foodType: e.target.value })}
                className={inputClass}>
                {['veg', 'non-veg', 'vegan', 'mixed'].map((t) => (
                  <option key={t} value={t}>{t}</option>
                ))}
              </select>
            </Field>

            <Field label="Quantity *">
              <div className="flex gap-2">
                <input type="number" required min={1} value={form.quantity}
                  onChange={(e) => setForm({ ...form, quantity: e.target.value })}
                  className={`${inputClass} w-24`} placeholder="10" />
                <select value={form.quantityUnit}
                  onChange={(e) => setForm({ ...form, quantityUnit: e.target.value })}
                  className={inputClass}>
                  {['kg', 'servings', 'portions', 'packs', 'litres'].map((u) => (
                    <option key={u} value={u}>{u}</option>
                  ))}
                </select>
              </div>
            </Field>
          </div>

          <Field label="Consume Before *">
            <input type="datetime-local" required value={form.expiresAt}
              onChange={(e) => setForm({ ...form, expiresAt: e.target.value })}
              className={inputClass} />
          </Field>

          <Field label="Handling Instructions">
            <input type="text" value={form.handlingInstructions}
              onChange={(e) => setForm({ ...form, handlingInstructions: e.target.value })}
              className={inputClass} placeholder="e.g. Keep refrigerated, reheat before serving" />
          </Field>

          <div className="grid grid-cols-2 gap-4">
            <Field label="Pickup Address *">
              <input type="text" required value={form['location.address']}
                onChange={(e) => setForm({ ...form, 'location.address': e.target.value })}
                className={inputClass} placeholder="Street address" />
            </Field>
            <Field label="City *">
              <input type="text" required value={form['location.city']}
                onChange={(e) => setForm({ ...form, 'location.city': e.target.value })}
                className={inputClass} placeholder="Lahore" />
            </Field>
          </div>

          <div className="flex gap-3 pt-2">
            <button type="button" onClick={() => navigate('/donor')}
              className="flex-1 bg-surface-800 hover:bg-surface-700 text-white font-medium py-3 rounded-xl text-sm transition-colors">
              Cancel
            </button>
            <button type="submit" disabled={loading}
              className="flex-1 bg-brand-600 hover:bg-brand-500 disabled:opacity-60 text-white font-semibold py-3 rounded-xl text-sm transition-colors">
              {loading ? 'Posting...' : 'Post Listing'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// Global static layout items (Moved OUTSIDE to avoid focus re-render bugs)
const Field = ({ label, children }) => (
  <div>
    <label className="block text-sm text-surface-200 mb-1.5">{label}</label>
    {children}
  </div>
);

const inputClass = "w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors";