import React, { useEffect, useState } from 'react';
import Navbar from '../components/ui/Navbar';
import api from '../lib/api';
import toast from 'react-hot-toast';
// 🌟 Custom Duolingo-style animation wrappers

import { DuoStaggerContainer, DuoStaggerItem, DuoButton } from '../components/ui/DuoInteractive';

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('stats');

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [statsRes, usersRes] = await Promise.all([
          api.get('/admin/stats'),
          api.get('/admin/users'),
        ]);
        setStats(statsRes.data.data);
        setUsers(usersRes.data.data);
      } catch {
        toast.error('Failed to load admin data.');
      } finally {
        setLoading(false);
      }
    };
    fetchAll();
  }, []);

  const handleVerify = async (id, current) => {
    try {
      await api.patch(`/admin/users/${id}/verify`);
      setUsers((prev) => prev.map((u) => u._id === id ? { ...u, isVerified: !current } : u));
      toast.success(current ? 'Donor unverified.' : 'Donor verified!');
    } catch {
      toast.error('Action failed.');
    }
  };

  const handleToggleActive = async (id, current) => {
    try {
      await api.patch(`/admin/users/${id}/toggle-active`);
      setUsers((prev) => prev.map((u) => u._id === id ? { ...u, isActive: !current } : u));
      toast.success(current ? 'User deactivated.' : 'User activated.');
    } catch {
      toast.error('Action failed.');
    }
  };

  const donors = users.filter((u) => u.role === 'donor');
  const receivers = users.filter((u) => u.role === 'receiver');

  return (
    <div className="min-h-screen bg-surface-950">
      <Navbar />
      <div className="max-w-7xl mx-auto px-4 py-8">
        <h1 className="text-2xl font-bold text-white mb-6">Admin Dashboard</h1>

        {/* Tabs */}
        <div className="flex gap-2 mb-6">
          {['stats', 'donors', 'receivers'].map((t) => (
            <button key={t} onClick={() => setTab(t)}
              className={`text-sm px-4 py-2 rounded-xl capitalize border transition-colors ${tab === t ? 'bg-brand-600 border-brand-500 text-white' : 'bg-surface-900 border-surface-800 text-surface-200 hover:border-surface-600'
                }`}>
              {t}
            </button>
          ))}
        </div>

        {loading ? <p className="text-surface-200">Loading...</p> : (
          <>
            {/* 🌟 STATS TAB WITH JUICY COMPONENT STAGGER */}
            {tab === 'stats' && stats && (
              <DuoStaggerContainer className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                {[
                  { label: 'Total Users', value: stats.totalUsers },
                  { label: 'Donors', value: stats.donors },
                  { label: 'Receivers', value: stats.receivers },
                  { label: 'Total Listings', value: stats.totalListings },
                  { label: 'Active Listings', value: stats.activeListings },
                  { label: 'Total Bookings', value: stats.totalBookings },
                  { label: 'Completed', value: stats.completedBookings },
                ].map(({ label, value }) => (
                  <DuoStaggerItem key={label} className="bg-surface-900 border border-surface-800 rounded-2xl p-5 shadow-sm">
                    <p className="text-3xl font-bold text-brand-400">{value}</p>
                    <p className="text-sm text-surface-200 mt-1">{label}</p>
                  </DuoStaggerItem>
                ))}
              </DuoStaggerContainer>
            )}

            {/* 🌟 USER LISTINGS TAB WITH RIPPLE CASCADE ENTRANCE */}
            {(tab === 'donors' || tab === 'receivers') && (
              <DuoStaggerContainer className="space-y-3">
                {(tab === 'donors' ? donors : receivers).map((u) => (
                  <DuoStaggerItem key={u._id} className="bg-surface-900 border border-surface-800 rounded-2xl p-4 flex flex-col sm:flex-row sm:items-center justify-between gap-3 shadow-sm">
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-medium text-white text-sm">{u.name}</p>
                        {u.organizationName && (
                          <span className="text-xs text-surface-200">· {u.organizationName}</span>
                        )}
                        {u.role === 'donor' && (
                          <span className={`text-xs px-1.5 py-0.5 rounded font-medium ${u.isVerified ? 'bg-green-900 text-green-300' : 'bg-yellow-900 text-yellow-300'
                            }`}>
                            {u.isVerified ? '✓ Verified' : 'Unverified'}
                          </span>
                        )}
                        {!u.isActive && (
                          <span className="text-xs bg-red-900 text-red-300 px-1.5 py-0.5 rounded">Inactive</span>
                        )}
                      </div>
                      <p className="text-xs text-surface-200 mt-0.5">{u.email} · {u.city || '—'}</p>
                    </div>

                    {/* Interactive Operational Control Action Triggers */}
                    <div className="flex gap-2 items-center">
                      {u.role === 'donor' && (
                        <DuoButton
                          onClick={() => handleVerify(u._id, u.isVerified)}
                          variant="secondary"
                          className="text-xs px-3 py-1.5"
                        >
                          {u.isVerified ? 'Revoke Verification' : 'Verify Donor'}
                        </DuoButton>
                      )}
                      <DuoButton
                        onClick={() => handleToggleActive(u._id, u.isActive)}
                        className={`text-xs px-3 py-1.5 ${u.isActive
                            ? 'bg-red-950 text-red-400 border-red-800 hover:bg-red-900/20'
                            : 'bg-brand-950 text-brand-400 border-brand-800 hover:bg-brand-900/20'
                          }`}
                      >
                        {u.isActive ? 'Deactivate' : 'Activate'}
                      </DuoButton>
                    </div>
                  </DuoStaggerItem>
                ))}

                {(tab === 'donors' ? donors : receivers).length === 0 && (
                  <p className="text-surface-200 text-sm">No {tab} registered yet.</p>
                )}
              </DuoStaggerContainer>
            )}
          </>
        )}
      </div>
    </div>
  );
}