import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/ui/Navbar';
import ListingCard from '../components/ui/ListingCard';
import useAuthStore from '../store/authStore';
import api from '../lib/api';
import toast from 'react-hot-toast';

export default function DonorDashboard() {
  const { user } = useAuthStore();
  const [listings, setListings] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [listRes, bookRes] = await Promise.all([
          api.get('/listings/my-listings'),
          api.get('/bookings/incoming'),
        ]);
        setListings(listRes.data.data);
        setBookings(bookRes.data.data);
      } catch {
        toast.error('Failed to load data.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm('Remove this listing?')) return;
    try {
      await api.delete(`/listings/${id}`);
      setListings((prev) => prev.filter((l) => l._id !== id));
      toast.success('Listing removed.');
    } catch {
      toast.error('Failed to remove listing.');
    }
  };

  return (
    <div className="min-h-screen bg-surface-950">
      <Navbar />
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
          <div>
            <h1 className="text-2xl font-bold text-white">
              {user?.organizationName || user?.name}
            </h1>
            <p className="text-surface-200 text-sm mt-0.5">
              {user?.isVerified
                ? '✅ Verified donor'
                : '⏳ Pending admin verification — you cannot post listings yet.'}
            </p>
          </div>
          {user?.isVerified && (
            <Link
              to="/donor/create"
              className="inline-flex items-center gap-2 bg-brand-600 hover:bg-brand-500 text-white font-semibold px-5 py-2.5 rounded-xl transition-colors text-sm"
            >
              + Log Excess Food
            </Link>
          )}
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-8">
          {[
            { label: 'Total Listings', value: listings.length },
            { label: 'Active', value: listings.filter((l) => l.status === 'available').length },
            { label: 'Claimed', value: listings.filter((l) => l.status === 'claimed').length },
            { label: 'Incoming Bookings', value: bookings.length },
          ].map(({ label, value }) => (
            <div key={label} className="bg-surface-900 border border-surface-800 rounded-2xl p-4">
              <p className="text-2xl font-bold text-white">{value}</p>
              <p className="text-xs text-surface-200 mt-0.5">{label}</p>
            </div>
          ))}
        </div>

        {/* Listings */}
        <h2 className="text-lg font-semibold text-white mb-4">My Listings</h2>
        {loading ? (
          <p className="text-surface-200">Loading...</p>
        ) : listings.length === 0 ? (
          <div className="text-center py-16 border border-dashed border-surface-800 rounded-2xl">
            <p className="text-surface-200 mb-4">No listings yet.</p>
            {user?.isVerified && (
              <Link to="/donor/create" className="text-brand-400 hover:text-brand-300 text-sm">
                Post your first listing →
              </Link>
            )}
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {listings.map((listing) => (
              <div key={listing._id} className="relative">
                <ListingCard listing={listing} />
                <button
                  onClick={() => handleDelete(listing._id)}
                  className="absolute top-3 left-3 bg-red-900/80 hover:bg-red-800 text-red-200 text-xs px-2 py-1 rounded-lg transition-colors"
                >
                  Remove
                </button>
              </div>
            ))}
          </div>
        )}

        {/* Incoming Bookings */}
        {bookings.length > 0 && (
          <div className="mt-10">
            <h2 className="text-lg font-semibold text-white mb-4">Incoming Claims</h2>
            <div className="space-y-3">
              {bookings.map((b) => (
                <div key={b._id} className="bg-surface-900 border border-surface-800 rounded-2xl p-4 flex items-center justify-between">
                  <div>
                    <p className="text-white font-medium text-sm">{b.listing?.title}</p>
                    <p className="text-surface-200 text-xs mt-0.5">
                      Claimed by {b.receiver?.organizationName || b.receiver?.name} · {b.receiver?.phone}
                    </p>
                  </div>
                  <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                    b.status === 'completed' ? 'bg-green-900 text-green-300' : 'bg-brand-900 text-brand-300'
                  }`}>
                    {b.status}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
