import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import useAuthStore from '../store/authStore';
import toast from 'react-hot-toast';

export default function RegisterPage() {
  const [form, setForm] = useState({
    name: '', email: '', password: '', role: 'receiver',
    organizationName: '', phone: '', city: '', address: '',
  });
  const { register, loading } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const result = await register(form);
    if (result.success) {
      toast.success('Account created!');
      navigate(form.role === 'donor' ? '/donor' : '/receiver');
    } else {
      toast.error(result.message);
    }
  };

  const isDonor = form.role === 'donor';

  return (
    <div className="min-h-screen bg-surface-950 flex items-center justify-center px-4 py-10">
      <div className="w-full max-w-sm">
        <div className="text-center mb-8">
          <span className="text-4xl">🌿</span>
          <h1 className="text-2xl font-bold text-white mt-2">RizqSaver</h1>
          <p className="text-surface-200 text-sm mt-1">Create your account</p>
        </div>

        <form onSubmit={handleSubmit} className="bg-surface-900 border border-surface-800 rounded-2xl p-6 space-y-4">
          {/* Role selector */}
          <div className="grid grid-cols-2 gap-2">
            {['receiver', 'donor'].map((r) => (
              <button
                key={r}
                type="button"
                onClick={() => setForm({ ...form, role: r })}
                className={`py-2.5 rounded-xl text-sm font-medium border transition-colors ${
                  form.role === r
                    ? 'bg-brand-600 border-brand-500 text-white'
                    : 'bg-surface-800 border-surface-700 text-surface-200 hover:border-surface-500'
                }`}
              >
                {r === 'donor' ? '🍽 Restaurant / Donor' : '🤝 Charity / Receiver'}
              </button>
            ))}
          </div>

          <div>
            <label className="block text-sm text-surface-200 mb-1.5">Full Name</label>
            <input type="text" required value={form.name}
              onChange={(e) => setForm({ ...form, name: e.target.value })}
              className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
              placeholder="Your full name" />
          </div>

          {isDonor && (
            <div>
              <label className="block text-sm text-surface-200 mb-1.5">Organization Name</label>
              <input type="text" value={form.organizationName}
                onChange={(e) => setForm({ ...form, organizationName: e.target.value })}
                className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
                placeholder="Restaurant or org name" />
            </div>
          )}

          <div>
            <label className="block text-sm text-surface-200 mb-1.5">Email</label>
            <input type="email" required value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
              className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
              placeholder="you@example.com" />
          </div>

          <div>
            <label className="block text-sm text-surface-200 mb-1.5">Password</label>
            <input type="password" required value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
              className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
              placeholder="Min 6 characters" />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-sm text-surface-200 mb-1.5">City</label>
              <input type="text" value={form.city}
                onChange={(e) => setForm({ ...form, city: e.target.value })}
                className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
                placeholder="Lahore" />
            </div>
            <div>
              <label className="block text-sm text-surface-200 mb-1.5">Phone</label>
              <input type="tel" value={form.phone}
                onChange={(e) => setForm({ ...form, phone: e.target.value })}
                className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
                placeholder="03xx-xxxxxxx" />
            </div>
          </div>

          {isDonor && (
            <div className="text-xs text-brand-400 bg-brand-900/30 border border-brand-800 rounded-xl p-3">
              ⓘ Donor accounts require admin verification before posting listings.
            </div>
          )}

          <button type="submit" disabled={loading}
            className="w-full bg-brand-600 hover:bg-brand-500 disabled:opacity-60 text-white font-semibold py-2.5 rounded-xl transition-colors text-sm">
            {loading ? 'Creating account...' : 'Create Account'}
          </button>
        </form>

        <p className="text-center text-sm text-surface-200 mt-4">
          Have an account?{' '}
          <Link to="/login" className="text-brand-400 hover:text-brand-300">Sign in</Link>
        </p>
      </div>
    </div>
  );
}
