import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import useAuthStore from '../../store/authStore';
import toast from 'react-hot-toast';

export default function Navbar() {
  const { user, logout } = useAuthStore();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    toast.success('Logged out.');
    navigate('/login');
  };

  return (
    <nav className="sticky top-0 z-50 bg-surface-950 border-b border-surface-800">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <Link to="/" className="flex items-center gap-2.5">
            <span className="text-2xl">🌿</span>
            <span className="font-bold text-white text-lg tracking-tight">RizqSaver</span>
          </Link>

          <div className="flex items-center gap-4">
            {user?.role === 'receiver' && (
              <Link
                to="/receiver/bookings"
                className="text-sm text-surface-200 hover:text-white transition-colors"
              >
                My Claims
              </Link>
            )}
            {user?.role === 'donor' && (
              <Link
                to="/donor/create"
                className="text-sm bg-brand-600 hover:bg-brand-500 text-white px-4 py-1.5 rounded-lg transition-colors font-medium"
              >
                + Log Food
              </Link>
            )}

            <div className="flex items-center gap-3">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-medium text-white">{user?.name}</p>
                <p className="text-xs text-surface-200 capitalize">{user?.role}</p>
              </div>
              <button
                onClick={handleLogout}
                className="text-sm text-surface-200 hover:text-white border border-surface-800 hover:border-surface-600 px-3 py-1.5 rounded-lg transition-colors"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
}
