import React, { useEffect, useState, useCallback } from 'react';
import Navbar from '../components/ui/Navbar';
import ListingCard from '../components/ui/ListingCard';
import api from '../lib/api';
import toast from 'react-hot-toast';

const FOOD_TYPES = ['all', 'veg', 'non-veg', 'vegan', 'mixed'];

export default function ReceiverDashboard() {
  const [listings, setListings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [claiming, setClaiming] = useState(null);
  const [search, setSearch] = useState('');
  const [foodType, setFoodType] = useState('all');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  const fetchListings = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams({ page, limit: 12 });
      if (search) params.append('search', search);
      if (foodType !== 'all') params.append('foodType', foodType);
      const res = await api.get(`/listings?${params}`);
      setListings(res.data.data);
      setTotalPages(res.data.pages);
    } catch {
      toast.error('Failed to load listings.');
    } finally {
      setLoading(false);
    }
  }, [page, search, foodType]);

  useEffect(() => {
    const delay = setTimeout(fetchListings, 300);
    return () => clearTimeout(delay);
  }, [fetchListings]);

  const handleClaim = async (listingId) => {
    setClaiming(listingId);
    try {
      await api.post(`/bookings/${listingId}`);
      toast.success('Batch claimed! Check your bookings.');
      setListings((prev) =>
        prev.map((l) => l._id === listingId ? { ...l, status: 'claimed' } : l)
      );
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to claim listing.');
    } finally {
      setClaiming(null);
    }
  };

  return (
    <div className="min-h-screen bg-surface-950">
      <Navbar />
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Header */}
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-white">Available Food Batches</h1>
          <p className="text-surface-200 text-sm mt-0.5">Browse and claim free food from local donors.</p>
        </div>

        {/* Filters */}
        <div className="flex flex-col sm:flex-row gap-3 mb-6">
          <input
            type="text"
            value={search}
            onChange={(e) => { setSearch(e.target.value); setPage(1); }}
            placeholder="Search food listings..."
            className="flex-1 bg-surface-900 border border-surface-800 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
          />
          <div className="flex gap-2 flex-wrap">
            {FOOD_TYPES.map((t) => (
              <button
                key={t}
                onClick={() => { setFoodType(t); setPage(1); }}
                className={`text-xs px-3 py-2 rounded-xl border capitalize transition-colors font-medium ${
                  foodType === t
                    ? 'bg-brand-600 border-brand-500 text-white'
                    : 'bg-surface-900 border-surface-800 text-surface-200 hover:border-surface-600'
                }`}
              >
                {t}
              </button>
            ))}
          </div>
        </div>

        {/* Grid */}
        {loading ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {[...Array(8)].map((_, i) => (
              <div key={i} className="bg-surface-900 border border-surface-800 rounded-2xl overflow-hidden animate-pulse">
                <div className="aspect-video bg-surface-800" />
                <div className="p-4 space-y-3">
                  <div className="h-4 bg-surface-800 rounded w-3/4" />
                  <div className="h-3 bg-surface-800 rounded w-1/2" />
                  <div className="h-9 bg-surface-800 rounded-xl" />
                </div>
              </div>
            ))}
          </div>
        ) : listings.length === 0 ? (
          <div className="text-center py-16 border border-dashed border-surface-800 rounded-2xl">
            <p className="text-surface-200">No listings found. Try a different search or filter.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {listings.map((listing) => (
              <ListingCard
                key={listing._id}
                listing={listing}
                onClaim={handleClaim}
                claiming={claiming === listing._id}
              />
            ))}
          </div>
        )}

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-center gap-2 mt-8">
            <button
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
              className="px-4 py-2 text-sm bg-surface-900 border border-surface-800 text-white rounded-xl disabled:opacity-40 hover:border-surface-600 transition-colors"
            >
              ← Prev
            </button>
            <span className="text-surface-200 text-sm">
              Page {page} of {totalPages}
            </span>
            <button
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="px-4 py-2 text-sm bg-surface-900 border border-surface-800 text-white rounded-xl disabled:opacity-40 hover:border-surface-600 transition-colors"
            >
              Next →
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
