import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import useAuthStore from '../store/authStore';
import toast from 'react-hot-toast';

export default function LoginPage() {
  const [form, setForm] = useState({ email: '', password: '' });
  const { login, loading } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const result = await login(form);
    if (result.success) {
      toast.success('Welcome back!');
      const role = result.user.role;
      navigate(role === 'donor' ? '/donor' : role === 'admin' ? '/admin' : '/receiver');
    } else {
      toast.error(result.message);
    }
  };

  return (
    <div className="min-h-screen bg-surface-950 flex items-center justify-center px-4">
      <div className="w-full max-w-sm">
        <div className="text-center mb-8">
          <span className="text-4xl">🌿</span>
          <h1 className="text-2xl font-bold text-white mt-2">RizqSaver</h1>
          <p className="text-surface-200 text-sm mt-1">Rescue food. Feed communities.</p>
        </div>

        <form onSubmit={handleSubmit} className="bg-surface-900 border border-surface-800 rounded-2xl p-6 space-y-4">
          <h2 className="text-lg font-semibold text-white">Sign in</h2>

          <div>
            <label className="block text-sm text-surface-200 mb-1.5">Email</label>
            <input
              type="email"
              required
              value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
              className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
              placeholder="you@example.com"
            />
          </div>

          <div>
            <label className="block text-sm text-surface-200 mb-1.5">Password</label>
            <input
              type="password"
              required
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
              className="w-full bg-surface-800 border border-surface-700 text-white rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-brand-500 transition-colors"
              placeholder="••••••••"
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-brand-600 hover:bg-brand-500 disabled:opacity-60 text-white font-semibold py-2.5 rounded-xl transition-colors text-sm"
          >
            {loading ? 'Signing in...' : 'Sign in'}
          </button>
        </form>

        <p className="text-center text-sm text-surface-200 mt-4">
          No account?{' '}
          <Link to="/register" className="text-brand-400 hover:text-brand-300">
            Register here
          </Link>
        </p>
      </div>
    </div>
  );
}
